def search_normalized(quran, query, min_ratio=0.6):
    nq=normalize_arabic(query)
    results=[]
    for rec in quran:
        nt=normalize_arabic(rec['ayah_text'])
        if nq in nt or nt in nq:
            results.append((1.0, rec))
        else:
            # approx ratio using difflib SequenceMatcher on nt
            ratio=difflib.SequenceMatcher(None, nq, nt).ratio()
            if ratio>=min_ratio:
                results.append((ratio, rec))
    results.sort(key=lambda x: -x[0])
    return results

res=search_normalized(quran, "إن الذين يتلون كتاب الله وأقاموا الصلاة وأنفقوا مما رزقناهم سرا وعلانية يرجون تجارة لن تبور", 0.6)
